#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int ans = 0, curMax = 0, x;
        for(int i=1;i<=N;i++){
            scanf("%d", &x);
            if(x > curMax) curMax = x;
            if(curMax == i) ans++;
        }
        printf("%d\n", ans);
    }
    return 0;
}

